export interface DKAccountInquiryRequest {
  request_id: string;
  account_number: string;
}

export interface DKAccountInquiryResponse {
  response_code: string;
  response_message: string;
  response_description: string;
  response_data?: {
    inquiry_id: string;
    beneficiary_account_name: string;
    account_number: string;
    balance_info: string;
    response_time: string;
  };
}

export interface DKClientInquiryRequest {
  request_id: string;
  id_type: string;
  id_number: string;
}

export interface DKClientInquiryResponse {
  response_code: string;
  response_message: string;
  response_description: string;
  response_data?: Array<{
    national_id: string;
    account_number: string;
    citizen_country: string;
    first_name: string;
    middle_name: string | null;
    last_name: string;
  }>;
}
